file_contents["CIS-A1-PDM_Problem_Definition_Matrix.md"] = """# Problem Definition Matrix\n\n**Document ID:** CIS-A1-PDM\n**CIS Layer:** Umbrella\n**Centauri Phase:** Centauri-0\n**TRL Target:** 1\n**Grid Slot:** U-001\n**PRECISELIENS Node:** Glass-0\n\n---\n\n## 1. Purpose\nDefine the mission need, operational constraints, and lunar relevance for the candidate technology. Establish the foundational problem statement that drives all downstream Centauri phases.\n\n## 2. Inputs\n- Artemis mission objectives\n- ConOps documentation\n- Known capability gaps\n- Environmental constraints (thermal, vacuum, dust, radiation)\n\n## 3. Outputs\n- Mission Need Statement (MNS)\n- Constraint matrix\n- Initial success criteria\n- Problem framing narrative\n\n## 4. Method\n1. Extract mission drivers from ConOps.\n2. Identify explicit and implicit capability gaps.\n3. Translate gaps into structured problem statements.\n4. Validate with cross-discipline review.\n\n## 5. Mission Integration\n- Maps to Artemis surface operations\n- Identifies EVA, logistics, and comms dependencies\n- Establishes early integration hooks\n\n## 6. TRL & SBIR Mapping\n- TRL: 1\n- SBIR: Pre-Phase I ideation\n\n## 7. Risks & Mitigations\n- **Risk:** Misalignment with evolving mission priorities\n  **Mitigation:** Refresh at each major review\n- **Risk:** Overly narrow framing\n  **Mitigation:** Include multi-domain review\n\n## 8. Change Log\n- 2026-05-17 — Initial creation\n"""
file_contents["CIS-A2-SFS_Scientific_Foundations_Scan.md"] = """# Scientific Foundations Scan\n\n**Document ID:** CIS-A2-SFS\n**CIS Layer:** Umbrella\n**Centauri Phase:** Centauri-1\n**TRL Target:** 1\n**Grid Slot:** U-002\n**PRECISELIENS Node:** Glass-1\n\n---\n\n## 1. Purpose\nSurvey scientific literature, NASA tech gap reports, and mission needs to establish the theoretical basis for the technology.\n\n## 2. Inputs\n- NASA Tech Gap Database\n- Peer-reviewed literature\n- Mission architecture documents\n- Prior SBIR awards\n\n## 3. Outputs\n- Scientific gap map\n- Foundational citations\n- Relevance justification\n- Early feasibility indicators\n\n## 4. Method\n1. Conduct literature review\n2. Extract relevant principles\n3. Map principles to mission needs\n4. Identify unresolved scientific questions\n\n## 5. Mission Integration\n- Aligns scientific basis with Artemis mission phases\n- Identifies where the technology reduces risk or cost\n\n## 6. TRL & SBIR Mapping\n- TRL: 1\n- SBIR: Pre-Phase I\n\n## 7. Risks & Mitigations\n- **Risk:** Outdated scientific assumptions\n  **Mitigation:** Annual refresh\n- **Risk:** Overgeneralization\n  **Mitigation:** Peer review\n\n## 8. Change Log\n- 2026-05-17 — Initial scan completed\n"""
file_contents["CIS-A3-CHS_Concept_Hypothesis_Sheet.md"] = """# Concept Hypothesis Sheet\n\n**Document ID:** CIS-A3-CHS\n**CIS Layer:** Umbrella\n**Centauri Phase:** Centauri-2\n**TRL Target:** 1–2\n**Grid Slot:** U-003\n**PRECISELIENS Node:** Glass-2\n\n---\n\n## 1. Purpose\nDefine the core mechanism, expected performance envelope, and conceptual behavior of the technology.\n\n## 2. Inputs\n- Problem Definition Matrix\n- Scientific Foundations Scan\n- Mission constraints\n\n## 3. Outputs\n- Hypothesis card\n- Expected performance envelope\n- Initial assumptions list\n\n## 4. Method\n1. Identify core mechanism\n2. Define expected behavior\n3. Establish bounding assumptions\n4. Validate conceptual coherence\n\n## 5. Mission Integration\n- Identifies mission phases where the concept applies\n- Establishes early interface assumptions\n\n## 6. TRL & SBIR Mapping\n- TRL: 1–2\n- SBIR: Pre-Phase I\n\n## 7. Risks & Mitigations\n- **Risk:** Incorrect assumptions\n  **Mitigation:** Track assumptions explicitly\n- **Risk:** Overly optimistic performance envelope\n  **Mitigation:** Use conservative bounds\n\n## 8. Change Log\n- 2026-05-17 — Hypothesis defined\n"""
file_contents["CIS-A4-FEM_Feasibility_Envelope_Model.md"] = """# Feasibility Envelope Model\n\n**Document ID:** CIS-A4-FEM\n**CIS Layer:** Umbrella\n**Centauri Phase:** Centauri-3\n**TRL Target:** 2\n**Grid Slot:** U-004\n**PRECISELIENS Node:** Glass-3\n\n---\n\n## 1. Purpose\nModel the feasibility bounds of the concept using early simulations and analytical methods.\n\n## 2. Inputs\n- Hypothesis Sheet\n- Scientific principles\n- Mission constraints\n- Environmental parameters\n\n## 3. Outputs\n- Feasibility envelope\n- Boundary conditions\n- Risk surfaces\n- Sensitivity analysis\n\n## 4. Method\n1. Identify key variables\n2. Build analytical or low-fidelity simulation models\n3. Sweep parameter space\n4. Identify feasibility regions\n\n## 5. Mission Integration\n- Determines whether the concept survives lunar environmental extremes\n- Identifies required shielding, power, or thermal controls\n\n## 6. TRL & SBIR Mapping\n- TRL: 2\n- SBIR: Pre-Phase I\n\n## 7. Risks & Mitigations\n- **Risk:** Model oversimplification\n  **Mitigation:** Document assumptions\n- **Risk:** Missing environmental factors\n  **Mitigation:** Cross-check with mission environment data\n\n## 8. Change Log\n- 2026-05-17 — Envelope established\n"""
file_contents["CIS-A5-UID_Umbrella_Integration_Draft.md"] = """# Umbrella Integration Draft\n\n**Document ID:** CIS-A5-UID\n**CIS Layer:** Umbrella\n**Centauri Phase:** Centauri-4\n**TRL Target:** 2\n**Grid Slot:** U-005\n**PRECISELIENS Node:** Glass-4\n\n---\n\n## 1. Purpose\nIntegrate the concept into the CIS Umbrella taxonomy, establishing lineage, classification, and governance.\n\n## 2. Inputs\n- Problem Definition Matrix\n- Feasibility Envelope\n- Hypothesis Sheet\n\n## 3. Outputs\n- Umbrella lineage map\n- Classification tags\n- Governance notes\n- Dependency graph\n\n## 4. Method\n1. Identify CIS category\n2. Map dependencies\n3. Define governance rules\n4. Establish lineage and naming\n\n## 5. Mission Integration\n- Ensures compatibility with CIS-wide architecture\n- Establishes early mission governance hooks\n\n## 6. TRL & SBIR Mapping\n- TRL: 2\n- SBIR: Pre-Phase I\n\n## 7. Risks & Mitigations\n- **Risk:** Misclassification\n  **Mitigation:** Umbrella review board\n- **Risk:** Missing dependencies\n  **Mitigation:** Cross-layer audit\n\n## 8. Change Log\n- 2026-05-17 — Umbrella integration drafted\n"""

